solution_code:
#include <stdio.h>
#include <stdlib.h>
#include <string.h>

int cmp_int(const void *a, const void *b) {
    int ia = *(const int *)a;
    int ib = *(const int *)b;
    return (ia > ib) - (ia < ib);
}

int cmp_str(const void *a, const void *b) {
    const char *sa = *(const char **)a;
    const char *sb = *(const char **)b;
    return strcmp(sa, sb);
}

int main(void) {
    int nums[] = {42, 7, 99, 3, 15};
    qsort(nums, 5, sizeof(int), cmp_int);
    printf("Entiers : ");
    for (int i = 0; i < 5; i++) printf("%d ", nums[i]);
    printf("\n");
    char *mots[] = {"delta", "alpha", "charlie", "bravo"};
    qsort(mots, 4, sizeof(char *), cmp_str);
    printf("Mots : ");
    for (int i = 0; i < 4; i++) printf("%s ", mots[i]);
    printf("\n");
    return 0;
}

